.db_row:
        | d7 = scroll row, compute source offset = d7 * 8
        move.l  d7,d4
    524a:	move.l d7,d4
        lsl.l   #3,d4                   | d4 = d7 * 8
    524c:	lsl.l #3,d4

        | --- Plane 1 (BPL2): left border from border_data+0*8192 ---
        move.l  a4,a0
    524e:	movea.l a4,a0
        adda.l  d4,a0
    5250:	adda.l d4,a0
        movem.l (a0),d0-d1
    5252:	movem.l (a0),d0-d1
        movem.l d0-d1,(a1)              | store to PF2 plane 1
    5256:	movem.l d0-d1,(a1)

        | --- Plane 3 (BPL4): left border from border_data+1*8192 ---
        move.l  a4,a0
    525a:	movea.l a4,a0
        adda.l  #8192,a0
    525c:	adda.l #8192,a0
        adda.l  d4,a0
    5262:	adda.l d4,a0
        movem.l (a0),d0-d1
    5264:	movem.l (a0),d0-d1
        movem.l d0-d1,(a2)              | store to PF2 plane 3
    5268:	movem.l d0-d1,(a2)

