        move.l  a4,a0
    526c:	movea.l a4,a0
        adda.l  #16384,a0
    526e:	adda.l #16384,a0
        adda.l  d4,a0
    5274:	adda.l d4,a0
        movem.l (a0),d0-d1
    5276:	movem.l (a0),d0-d1
        movem.l d0-d1,(a6)              | store to PF2 plane 5
    527a:	movem.l d0-d1,(a6)

