    528c:	movea.l a5,a0
        adda.l  #8192,a0
    528e:	adda.l #8192,a0
        adda.l  d4,a0
    5294:	adda.l d4,a0
        movem.l (a0),d0-d1
    5296:	movem.l (a0),d0-d1
        movem.l d0-d1,32(a2)
    529a:	movem.l d0-d1,32(a2)

