        addi.w  #30,d2           | d2 went < 0, restore remainder
    563e:	addi.w #30,d2
        bra.s   .aef_mod_done
    5642:	bra.s 5648 <.aef_mod_done>

00005644 <.aef_mod_cont>:
.aef_mod_cont:
        dbra    d3,.aef_mod
    5644:	dbf d3,5638 <.aef_mod>

00005648 <.aef_mod_done>:
.aef_mod_done:
